VALUES ('default', '{"fa":"شرکت مهندسی فراتک (خودرو سبز)","en":"Faratech Engineering Company"}'::jsonb, '{"fa":"تسهیل امور و زندگی معلولان، بالابردن سطح صنعت در کشور، ساخت مجموعه‌ی حرفه‌ای"}'::jsonb, '{"fa":"بومی‌سازی صنعت تجهیزات پزشکی در کشور با بالاترین فناوری روز دنیا، دست‌اندازی به بخش‌های دیگر صنایع مهندسی کشور مانند جک‌های پالت، استاکر، ماشین‌آلات صنعتی"}'::jsonb, '{"fa":"ابتدا بنیانگذاران شرکت را جهت تولید خودرو، موتور و اسکوترهای برقی در سطح جهانی تأسیس کردند. به‌واسطه نیازمندی‌های آن زمان و فضای درآمدسازی بهتر، به تولید ویلچرهای برقی روی آوردند. ویلچرهای فاتح ۱۱۰ شرکت فراتک با محبوبیت زیاد روبه‌رو شد و ویلچرهای چینی را برای مدتی طولانی از بازار ایران حذف کرد. شرکت روزبه‌روز پیشرفت کرد و به تولید باکیفیت و علمی در سطح جهانی ادامه داد. ویلچرها طراحی‌های منحصربه‌فردی دارند که در دنیا شبیه ندارد و از نظر فنی، قدرتی و مهندسی در سطح جهانی هستند. شرکت به‌صورت انحصاری بخش عمده‌ای از واردات قطعات و ویلچرهای خاص را انجام می‌دهد و در میان بهترین واردکنندگان بازار ایران قرار دارد. محصولات از بهترین قطعات تایوانی مانند موتور، کامپیوتر، جوی‌استیک و چرخ‌ها بهره می‌برند، اما طراحی، تولید و ساخت کاملاً متعلق به خود شرکت است. این شرکت از سال ۱۳۷۹ با رویکرد طراحی و تولید تجهیزات پزشکی و توانبخشی، در تلاش برای تسهیل فعالیت‌های روزمره جانبازان، معلولان و سالمندان بوده و با ارائه محصولات باکیفیت و خدمات پس از فروش مطلوب، نامی آشنا در صنعت توانبخشی کشور است. همچنین با بررسی بازارهای هدف خارج از ایران، به‌دنبال فراگیر کردن برند خود در سطح جهانی است."}'::jsonb, '[{"name":"کارت بازرگانی (اتاق بازرگانی و صنایع و معادن ایران)"},{"name":"پروانه ساخت اداره کل (آیمد، سازمان غذا و دارو)"},{"name":"ISO 13485"}]'::jsonb, '{"phones":["021-77516927","021-77516928","09195372663"],"emails":["faratech-ev@gmail.com","faratech.co@gmail.com"],"address":{"fa":"تهران، خیابان شریعتی، بالاتر از خیابان سمیّه، پلاک ۱۰۶، دفتر مرکزی شرکت مهندسی فراتک"},"social":{"instagram":"faratech.co","whatsapp":"989195372663","bale":"989195372663"}}'::jsonb)
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, mission = EXCLUDED.mission, vision = EXCLUDED.vision,
  history = EXCLUDED.history, certificates = EXCLUDED.certificates, contact = EXCLUDED.contact;

-- category_copy
INSERT INTO public.category_copy (slug, category_key, title, short_description, full_description, usage, target_audience) VALUES (
  'power-wheelchairs', 'POWER_WHEELCHAIRS'::public.product_category_key,
  '{"fa":"ویلچرهای برقی"}'::jsonb,
  '{"fa":"ویلچرهای برقی فراتک با هدف افزایش استقلال حرکتی، راحتی کاربر و پاسخگویی به نیازهای مختلف توانبخشی طراحی و عرضه می‌شوند. این محصولات در مدل‌های متنوع تاشو و مبله، با امکانات و تجهیزات مختلف، برای استفاده در محیط‌های داخلی، فضاهای شهری و شرایط تخصصی‌تر قابل ارائه هستند. بهره‌گیری از قطعات باکیفیت وارداتی، طراحی مهندسی‌شده و امکان انتخاب تجهیزات متناسب با نیاز هر کاربر، از ویژگی‌های اصلی ویلچرهای برقی فراتک است."}'::jsonb,
  '{"fa":"ویلچرهای برقی فراتک راهکاری پیشرفته برای افرادی هستند که به دنبال استقلال بیشتر، راحتی بالاتر و قابلیت جابجایی بدون نیاز به نیروی فیزیکی هستند. این محصولات با تکیه بر رویکرد مهندسی و استفاده از قطعات باکیفیت وارداتی، برای پاسخگویی به نیازهای متنوع کاربران در شرایط مختلف طراحی و عرضه می‌شوند. سبد محصولات ویلچر برقی فراتک شامل مدل‌های تاشو و مبله با امکانات متنوع است که هر یک متناسب با شرایط فیزیکی، سطح فعالیت و محیط استفاده کاربر قابل انتخاب هستند. طراحی و کیفیت ساخت: در طراحی ویلچرهای برقی فراتک، عواملی مانند پایداری، ایمنی، راحتی کاربر و قابلیت اطمینان در اولویت قرار دارند. بسیاری از قطعات اصلی از جمله جوی‌استیک کنترل، موتور، سیستم کنترل الکترونیکی، چرخ‌ها و بخش قابل توجهی از تجهیزات فنی از تولیدکنندگان معتبر تایوانی و بین‌المللی تأمین می‌شوند تا عملکردی پایدار و قابل اعتماد در استفاده روزمره فراهم شود. تنوع در پیکربندی: ویلچرهای برقی فراتک با توجه به نیاز کاربران در پیکربندی‌های مختلف قابل عرضه هستند، از جمله:مدل‌های تاشو و قابل حمل، مدل‌های مبله با شاسی تقویت‌شده، صندلی‌های استاندارد و XL، بدنه فولادی یا آلومینیومی، چرخ‌های بادی یا توپر، باتری‌های UPS و لیتیومی، موتورهای با توان‌های مختلف، جوی‌استیک و سیستم‌های کنترل متنوع، چراغ و تجهیزات روشنایی، دسته‌ها و جاپایی‌های ارتوپدی، سیستم‌های تنظیم ارتفاع و جک برقی، مدل‌های ایستا (Standing) ،رنگ‌بندی و تجهیزات سفارشی. این تنوع امکان انتخاب ویلچری متناسب با شرایط جسمی، سبک زندگی و نیازهای درمانی هر کاربر را فراهم می‌کند. عملکرد و قابلیت حرکت :مدل‌های مختلف ویلچر برقی فراتک از نظر قدرت موتور، ظرفیت باتری، ابعاد چرخ‌ها و توان عبور از موانع در سطوح مختلفی عرضه می‌شوند. برخی مدل‌ها برای استفاده روزمره در محیط‌های داخلی طراحی شده‌اند و برخی دیگر با بهره‌گیری از چرخ‌های بزرگ‌تر، سیستم تعلیق مناسب‌تر و توان حرکتی بالاتر، قابلیت حرکت در مسیرهای شهری، سطوح ناهموار و فضاهای باز را دارند. رویکرد فراتک: فراتک تلاش می‌کند در کنار ارائه محصولات متنوع، راهکار مناسب هر کاربر را بر اساس نیاز واقعی او پیشنهاد دهد. به همین دلیل انتخاب تجهیزات، مشخصات فنی و امکانات هر ویلچر با در نظر گرفتن شرایط استفاده، میزان تحرک مورد نیاز و راحتی بلندمدت کاربر انجام می‌شود."}'::jsonb,
  '{"fa":"ویلچرهای برقی برای افرادی طراحی شده‌اند که نیاز به جابجایی مستقل با حداقل فشار فیزیکی دارند. این محصولات در محیط‌های خانگی، مراکز درمانی، فضاهای شهری، محیط‌های کاری، مراکز آموزشی و فعالیت‌های روزمره کاربرد دارند و بسته به نوع تجهیز می‌توانند برای استفاده داخل ساختمان یا تردد در فضاهای باز و مسیرهای ناهموار مورد استفاده قرار گیرند."}'::jsonb,
  '{"fa":"کاربران دارای محدودیت حرکتی موقت یا دائمی، کاربران نیازمند جابجایی مستقل در طول روز، سالمندان با توان حرکتی محدود، افراد دارای آسیب‌های نخاعی و بیماری‌های عصبی-عضلانی، مراکز توانبخشی و درمانی، مراکز نگهداری و مراقبتی، سازمان‌ها و مجموعه‌های ارائه‌دهنده خدمات توانبخشی، کاربرانی که به امکانات تخصصی مانند سیستم ایستا، جک برقی یا تجهیزات ارتوپدی نیاز دارند."}'::jsonb
) ON CONFLICT (slug) DO UPDATE SET
  category_key = EXCLUDED.category_key,
  title = EXCLUDED.title,
  short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description,
  usage = EXCLUDED.usage,
  target_audience = EXCLUDED.target_audience;
INSERT INTO public.category_copy (slug, category_key, title, short_description, full_description, usage, target_audience) VALUES (
  'manual-wheelchairs', 'MANUAL_WHEELCHAIRS'::public.product_category_key,
  '{"fa":"ویلچرهای دستی"}'::jsonb,
  '{"fa":"ویلچرهای دستی فراتک با تکیه بر دانش مهندسی و تجربه تخصصی در حوزه تجهیزات توانبخشی، برای پاسخگویی به نیازهای متنوع کاربران طراحی و عرضه می‌شوند. این محصولات در مدل‌های استاندارد و اسپرت، با امکان انتخاب شاسی فولادی یا آلومینیومی، ابعاد مختلف و انواع چرخ، قابلیت تطبیق با شرایط و نیازهای گوناگون را دارند. تمرکز فراتک بر ارائه محصولاتی با کیفیت ساخت مناسب، دوام بالا، راحتی کاربر و عملکرد قابل اعتماد در استفاده روزمره و تخصصی است."}'::jsonb,
  '{"fa":"ویلچرهای دستی فراتک با تمرکز بر اصول مهندسی، دوام سازه، ارگونومی و قابلیت سفارشی‌سازی طراحی و تولید می‌شوند؛ این محصولات با هدف پاسخگویی به نیاز طیف گسترده‌ای از کاربران، از استفاده روزمره تا کاربردهای تخصصی و ورزشی، توسعه یافته‌اند. در فراتک، انتخاب ویلچر تنها به ابعاد یا ظاهر محصول محدود نمی‌شود؛ هر ویلچر بر اساس شرایط فیزیکی کاربر، محیط استفاده و سطح فعالیت مورد انتظار قابل پیکربندی است تا بهترین تعادل میان راحتی، استحکام و عملکرد حاصل شود. ساختار و متریال: شاسی مهم‌ترین بخش هر ویلچر است و تأثیر مستقیمی بر دوام، وزن و کیفیت حرکت دارد. ویلچرهای دستی فراتک بسته به نیاز مشتری با دو نوع ساختار اصلی عرضه می‌شوند: شاسی فولادی: شاسی‌های فولادی به دلیل استحکام بالا و مقاومت مناسب در استفاده مداوم، گزینه‌ای قابل اعتماد برای کاربردهای روزمره، مراکز درمانی و استفاده طولانی‌مدت محسوب می‌شوند. ویژگی‌ها: استحکام مکانیکی بالا، دوام طولانی، قابلیت تحمل بار مناسب، هزینه نگهداری پایین. شاسی آلومینیومی: مدل‌های آلومینیومی با هدف کاهش وزن و بهبود سهولت جابجایی طراحی شده‌اند و برای کاربران فعال‌تر گزینه مناسبی هستند. ویژگی‌ها: وزن کمتر نسبت به مدل‌های فولادی، سهولت حمل و نقل، مقاومت مناسب در برابر خوردگی، راندمان حرکتی بهتر. ابعاد و ارگونومی: ویلچرهای دستی فراتک در ابعاد استاندارد و XL تولید یا عرضه می‌شوند تا نیاز کاربران با شرایط فیزیکی متفاوت را پوشش دهند. طراحی ابعاد نشیمن، پشتی و موقعیت قرارگیری کاربر بر اساس اصول ارگونومی انجام شده تا علاوه بر راحتی، پایداری و کنترل مناسب ویلچر نیز حفظ شود. انواع چرخ و پیکربندی حرکتی - بسته به نوع کاربرد، امکان انتخاب انواع مختلف چرخ وجود دارد: چرخ توپر بدون نیاز به نگهداری و مقاوم در برابر پنچری، چرخ بادی مجهز به رینگ رانش برای حرکت نرم‌تر و راحت‌تر، چرخ توپر مجهز به رینگ رانش برای ترکیب دوام و سهولت استفاده. این تنوع امکان انتخاب ویلچر متناسب با شرایط محیطی و سبک استفاده هر کاربر را فراهم می‌کند. ویلچرهای اسپرت فراتک: برای کاربران فعال و ورزشکاران، فراتک ویلچرهای اسپرت را نیز در سبد محصولات خود ارائه می‌دهد. در این مدل‌ها هندسه شاسی، توزیع وزن، موقعیت نشیمن و ساختار چرخ‌ها با هدف افزایش چابکی، کاهش اتلاف انرژی و بهبود کنترل طراحی شده است؛ نتیجه این رویکرد، ویلچری سبک‌تر، سریع‌تر و پاسخگوتر در حرکت است. ویلچرهای اسپرت فراتک می‌توانند برای استفاده روزمره فعال، تمرینات ورزشی و کاربردهای تخصصی مورد استفاده قرار گیرند. راهکارهای تخصصی‌تر: علاوه بر محصولات تولیدی، فراتک امکان تأمین ویلچرهای تخصصی وارداتی از جمله مدل‌های فوق سبک، ویلچرهای حرفه‌ای ورزشی و نمونه‌های ساخته شده از مواد پیشرفته مانند فیبر کربن را نیز فراهم کرده است تا کاربران بتوانند متناسب با نیاز خود از میان طیف گسترده‌ای از راهکارهای حرکتی انتخاب کنند. رویکرد فراتک: تمرکز اصلی فراتک بر ارائه راهکارهای مهندسی‌شده در حوزه تجهیزات توانبخشی است؛ به همین دلیل در انتخاب یا طراحی هر محصول، عواملی مانند کیفیت ساخت، دوام، قابلیت اطمینان، راحتی کاربر و امکان سفارشی‌سازی در اولویت قرار می‌گیرند. هدف ما ارائه محصولی است که علاوه بر عملکرد مناسب در روز اول، در استفاده مستمر و طولانی‌مدت نیز پاسخگوی نیاز کاربر باقی بماند."}'::jsonb,
  '{"fa":"ویلچرهای دستی یکی از پرکاربردترین تجهیزات توانبخشی هستند که برای جابجایی ایمن و راحت افراد دارای محدودیت حرکتی مورد استفاده قرار می‌گیرند. این محصولات در محیط‌های خانگی، مراکز درمانی، بیمارستان‌ها، مراکز توانبخشی، فضاهای عمومی و فعالیت‌های روزمره کاربرد دارند. بسته به نوع طراحی و پیکربندی، ویلچرهای دستی می‌توانند برای استفاده موقت، بلندمدت یا فعالیت‌های تخصصی و ورزشی مورد استفاده قرار گیرند."}'::jsonb,
  '{"fa":"ویلچرهای دستی فراتک برای طیف گسترده‌ای از کاربران طراحی و عرضه می‌شوند از جمله افراد دارای محدودیت حرکتی موقت یا دائمی، سالمندان نیازمند به جابجایی آسان‌تر، مراکز درمانی بیمارستان‌ها و کلینیک‌ها، مراکز توانبخشی و مراقبتی، کاربران فعال و مستقل در زندگی روزمره، ورزشکاران و کاربران نیازمند ویلچرهای اسپرت، سازمان‌ها و مجموعه‌های ارائه‌دهنده خدمات درمانی و توانبخشی. تنوع در ابعاد، متریال و تجهیزات جانبی این امکان را فراهم می‌کند که هر کاربر متناسب با نیازهای خود، گزینه مناسب را انتخاب کند."}'::jsonb
) ON CONFLICT (slug) DO UPDATE SET
  category_key = EXCLUDED.category_key,
  title = EXCLUDED.title,
  short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description,
  usage = EXCLUDED.usage,
  target_audience = EXCLUDED.target_audience;
INSERT INTO public.category_copy (slug, category_key, title, short_description, full_description, usage, target_audience) VALUES (
  'shower-wheelchairs', 'MOBILITY_AIDS'::public.product_category_key,
  '{"fa":"ویلچرهای حمامی"}'::jsonb,
  '{"fa":"ویلچرهای حمام و توالت فراتک برای تسهیل امور بهداشتی، استحمام و جابجایی ایمن افراد دارای محدودیت حرکتی طراحی شده‌اند. این محصولات با ساختار مقاوم در برابر رطوبت، طراحی کاربردی و استفاده از قطعات باکیفیت تایوانی، امکان استفاده راحت در محیط‌های بهداشتی و مرطوب را فراهم می‌کنند."}'::jsonb,
  '{"fa":"ویلچرهای حمام و توالت فراتک با هدف افزایش راحتی کاربر و تسهیل فرآیند مراقبت‌های روزمره طراحی و عرضه می‌شوند. این محصولات امکان استفاده در محیط‌های مرطوب، حمام و سرویس بهداشتی را فراهم کرده و نیاز به جابجایی‌های مکرر کاربر را کاهش می‌دهند. در طراحی این ویلچرها عواملی مانند ایمنی، پایداری، سهولت نظافت، مقاومت در برابر رطوبت و راحتی کاربر در اولویت قرار گرفته است. ساختار مقاوم، تجهیزات مناسب برای محیط‌های مرطوب و طراحی ارگونومیک نشیمن، استفاده طولانی‌مدت از محصول را آسان‌تر می‌کند. ویلچرهای حمام و توالت فراتک در مدل‌های مختلف و با امکانات متنوع عرضه می‌شوند تا متناسب با شرایط فیزیکی و نیازهای مراقبتی هر کاربر انتخاب شوند. همچنین بخش مهمی از قطعات از جمله چرخ‌ها و مجموعه نشیمن از تأمین‌کنندگان معتبر تایوانی انتخاب می‌شوند که به دلیل کیفیت ساخت، دوام و عملکرد مناسب، از گزینه‌های شناخته‌شده در این حوزه محسوب می‌شوند."}'::jsonb,
  '{"fa":"استفاده در حمام و محیط‌های مرطوب، استفاده در سرویس‌های بهداشتی فرنگی، جابجایی ایمن کاربران دارای محدودیت حرکتی، استفاده در مراکز درمانی و توانبخشی، استفاده در مراکز نگهداری و مراقبتی، کمک به انجام امور بهداشتی روزمره با سهولت بیشتر، کاهش نیاز به انتقال‌های مکرر کاربر بین تجهیزات مختلف."}'::jsonb,
  '{"fa":"افراد دارای محدودیت حرکتی موقت یا دائمی، سالمندان نیازمند کمک در امور بهداشتی، افراد دارای آسیب‌های نخاعی و بیماری‌های عصبی-عضلانی، مراکز توانبخشی و فیزیوتراپی، بیمارستان‌ها و مراکز درمانی، مراکز نگهداری سالمندان، مراقبین و خانواده‌هایی که از افراد دارای محدودیت حرکتی نگهداری می‌کنند."}'::jsonb
) ON CONFLICT (slug) DO UPDATE SET
  category_key = EXCLUDED.category_key,
  title = EXCLUDED.title,
  short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description,
  usage = EXCLUDED.usage,
  target_audience = EXCLUDED.target_audience;
INSERT INTO public.category_copy (slug, category_key, title, short_description, full_description, usage, target_audience) VALUES (
  'patient-lifts', 'MOBILITY_AIDS'::public.product_category_key,
  '{"fa":"بالابرهای بیمار"}'::jsonb,
  '{"fa":"لیفت‌های انتقال بیمار فراتک برای جابجایی ایمن و کنترل‌شده افراد دارای محدودیت حرکتی طراحی شده‌اند. این محصولات با هدف کاهش فشار فیزیکی بر بیمار و مراقب، امکان انتقال راحت بین تخت، ویلچر، سرویس بهداشتی و سایر موقعیت‌های روزمره را فراهم می‌کنند."}'::jsonb,
  '{"fa":"لیفت‌های انتقال بیمار فراتک راهکاری تخصصی برای جابجایی ایمن افراد دارای محدودیت حرکتی در محیط‌های خانگی، مراکز درمانی و مراکز مراقبتی هستند. این تجهیزات با هدف کاهش خطر آسیب‌های ناشی از جابجایی دستی و افزایش ایمنی بیمار و مراقب طراحی و تولید می‌شوند. سبد محصولات فراتک شامل انواع لیفت‌های بیمار با کاربردهای مختلف است؛ از لیفت‌های انتقال بیمار مجهز به بازو و سیستم بالابر برای جابجایی بین تخت، ویلچر و سایر تجهیزات، تا سیستم‌های بالابر صندلی که امکان بلند کردن یا تغییر ارتفاع کاربر را با کنترل آسان فراهم می‌کنند. در طراحی این محصولات عواملی مانند پایداری سازه، سهولت استفاده، ایمنی در حین انتقال، کیفیت قطعات و راحتی کاربر در اولویت قرار گرفته است. استفاده از ساختار مهندسی‌شده، مکانیزم‌های مطمئن انتقال و طراحی مناسب باعث می‌شود فرآیند جابجایی با کمترین فشار و بیشترین اطمینان انجام شود. لیفت‌های فراتک در مدل‌ها و ظرفیت‌های مختلف عرضه می‌شوند تا متناسب با شرایط جسمی کاربر، محیط استفاده و نیازهای مراقبتی انتخاب شوند."}'::jsonb,
  '{"fa":"انتقال بیمار بین تخت و ویلچر، انتقال بیمار به سرویس بهداشتی یا حمام، کمک به جابجایی افراد دارای محدودیت حرکتی شدید، کاهش فشار فیزیکی بر مراقبین و کادر درمان، استفاده در منازل، مراکز درمانی و توانبخشی، افزایش ایمنی در فرآیند جابجایی بیمار، کمک به مراقبت روزمره از سالمندان و بیماران."}'::jsonb,
  '{"fa":"افراد دارای محدودیت حرکتی شدید، افراد دارای آسیب‌های نخاعی، سالمندان نیازمند مراقبت مستمر، بیماران بستری در منزل، مراکز توانبخشی و فیزیوتراپی، بیمارستان‌ها و مراکز درمانی، مراکز نگهداری سالمندان، مراقبین و خانواده‌های درگیر با جابجایی روزانه بیمار."}'::jsonb
) ON CONFLICT (slug) DO UPDATE SET
  category_key = EXCLUDED.category_key,
  title = EXCLUDED.title,
  short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description,
  usage = EXCLUDED.usage,
  target_audience = EXCLUDED.target_audience;
INSERT INTO public.category_copy (slug, category_key, title, short_description, full_description, usage, target_audience) VALUES (
  'mobility-scooters', 'MOBILITY_AIDS'::public.product_category_key,
  '{"fa":"اسکوترهای حرکتی"}'::jsonb,
  '{"fa":"اسکوترهای برقی فراتک راهکاری کاربردی برای افزایش استقلال حرکتی افراد دارای محدودیت در راه رفتن یا خستگی ناشی از جابجایی‌های طولانی هستند. این محصولات با طراحی پایدار، کنترل آسان و امکانات متنوع، برای استفاده روزمره در محیط‌های داخلی و فضاهای شهری طراحی شده‌اند و امکان تردد راحت و ایمن را برای کاربران فراهم می‌کنند."}'::jsonb,
  '{"fa":"اسکوترهای برقی فراتک با هدف فراهم کردن تحرک مستقل، راحت و ایمن برای افرادی طراحی شده‌اند که توانایی راه رفتن طولانی‌مدت را ندارند یا برای جابجایی روزمره به کمک نیاز دارند. این محصولات ترکیبی از راحتی، پایداری و سهولت استفاده را ارائه می‌دهند و برای استفاده در محیط‌های شهری، مراکز خرید، مجموعه‌های درمانی، فضاهای عمومی و محیط‌های مسکونی مناسب هستند. در طراحی اسکوترهای برقی فراتک، عواملی مانند راحتی نشیمن، پایداری در حرکت، شعاع گردش مناسب، سهولت کنترل و قابلیت اطمینان در استفاده روزمره مورد توجه قرار گرفته است. صندلی‌های راحت، سیستم فرمان ساده، تجهیزات روشنایی، سبد حمل وسایل و امکانات جانبی مختلف، تجربه استفاده از محصول را بهبود می‌بخشند. اسکوترهای برقی فراتک در مدل‌های مختلف با ابعاد، ظرفیت باتری، قدرت موتور، امکانات رفاهی و مشخصات حرکتی متنوع عرضه می‌شوند تا کاربران بتوانند متناسب با شرایط فیزیکی، محیط استفاده و نیازهای روزمره خود گزینه مناسب را انتخاب کنند."}'::jsonb,
  '{"fa":"جابجایی روزمره در محیط‌های شهری، تردد در مراکز خرید و فضاهای عمومی، استفاده در مجتمع‌های مسکونی و محوطه‌های بزرگ، استفاده در مراکز درمانی و توانبخشی، کمک به حفظ استقلال حرکتی کاربران، کاهش خستگی ناشی از راه رفتن طولانی‌مدت، جابجایی راحت در محیط‌های داخلی و خارجی."}'::jsonb,
  '{"fa":"سالمندان دارای محدودیت در راه رفتن، افراد دارای مشکلات حرکتی خفیف تا متوسط، کاربران نیازمند جابجایی مستقل در فواصل طولانی، افراد در دوران نقاهت و بازتوانی، مراکز درمانی و توانبخشی، مجتمع‌های اقامتی و مراقبتی، افرادی که به دنبال وسیله‌ای راحت برای تردد روزمره هستند."}'::jsonb
) ON CONFLICT (slug) DO UPDATE SET
  category_key = EXCLUDED.category_key,
  title = EXCLUDED.title,
  short_description = EXCLUDED.short_description,
  full_description = EXCLUDED.full_description,
  usage = EXCLUDED.usage,
  target_audience = EXCLUDED.target_audience;

