  '[{"fa":"قابلیت تاشو با باتری"},{"fa":"زیر آرنجی متحرک (قابل تنظیم ارتفاع)"},{"fa":"زیرپایی متحرک (قابل تنظیم ارتفاع)"},{"fa":"سیستم کنترلر DYNAMIC یا P&G"}]'::jsonb,
